action.command:
cd /workspace/puppeteer && node - <<'NODE'
const fs=require('fs'); const path=require('path');
function walk(dir){ for(const e of fs.readdirSync(dir,{withFileTypes:true})){ if(e.name==='node_modules'||e.name==='.git') continue; const p=path.join(dir,e.name); if(e.isDirectory()) walk(p); else if(e.name==='package.json'){ const j=JSON.parse(fs.readFileSync(p,'utf8')); if(j.scripts){ console.log('\n# '+path.relative(process.cwd(),p)); for(const [k,v] of Object.entries(j.scripts)){ if(/test|unit|build|type|lint/.test(k)) console.log(k+': '+v); } } } } }
walk('packages');
NODE

